// Stub: previously enabled COEP/COOP for cross-origin isolation, but blocked
// cross-origin iframes. The SPA no longer needs isolation; this stub
// unregisters itself so old clients clean up on update check.
self.addEventListener('install', () => self.skipWaiting());
self.addEventListener('activate', (event) => {
  event.waitUntil(
    self.registration.unregister()
      .then(() => self.clients.matchAll())
      .then((clients) => { for (const c of clients) c.navigate(c.url); })
  );
});
